import { extendTheme } from "@chakra-ui/react";

const theme = extendTheme({
  colors: {
    brand: {
      500: "#A435F0",
      600: "#8710D8",
    },
  },
  styles: {
    global: {
      body: {
        bg: "#FFFFFF",
        color: "#1C1D1F",
      },
    },
  },
  components: {
    Button: {
      baseStyle: {
        borderRadius: "md",
        fontWeight: "600",
      },
      variants: {
        solid: {
          bg: "brand.500",
          color: "white",
          _hover: {
            bg: "brand.600",
          },
        },
      },
    },
    Card: {
      baseStyle: {
        p: 4,
        borderRadius: "lg",
        border: "1px solid #E5E7EB",
        boxShadow: "sm",
        transition: "0.3s",
        _hover: {
          transform: "translateY(-5px)",
          boxShadow: "lg",
        },
      },
    },
  },
});

export default theme;
